def count_by_category(complaints):
    counts = {}
    for c in complaints:
        cat = c['category']
        counts[cat] = counts.get(cat, 0) + 1
    return counts

def validate_aadhaar(number):
    s = str(number).strip()
    if len(s) != 12:
        return False
    if not s.isdigit():
        return False
    if s[0] in ('0', '1'):
        return False
    return True
